// PER-TAB STAFF PERMISSIONS
// Preset roles set a baseline; per-person overrides fine-tune each tab to
// hidden / view-only / editable. Access maps onto the permission flags the app
// already reads everywhere, so the existing edit-gates enforce view-only.
// ─────────────────────────────────────────────
const PERMISSION_TABS = [
  { id: "dashboard", label: "Home",      editable: false, view: [],            edit: [] },
  { id: "clients",   label: "Clients",   editable: true,  view: ["seeBalances"], edit: ["seeBalances", "editClients", "editHistory", "canImport"] },
  { id: "schedule",  label: "Schedule",  editable: true,  view: [],            edit: ["editSchedule", "completeStops", "sendTexts"] },
  { id: "invoices",  label: "Invoices",  editable: true,  view: ["viewInvoices"], edit: ["viewInvoices", "canInvoice"] },
  { id: "inventory", label: "Inventory", editable: true,  view: ["seeInventory"], edit: ["seeInventory", "editInventory"] },
  { id: "estimates", label: "Estimates", editable: true,  view: ["canInvoice"], edit: ["canInvoice"] },
  // Comms is one tab with per-section access (Messages / Inbox / Reminders / Broadcast / Settings /
  // Log). The tab toggle is the master (Hidden/Visible); which sections show is fine-tuned in the
  // staff editor's Advanced permissions → Comms sections. Visible grants sendTexts for the composer.
  { id: "comms",     label: "Comms",     editable: false, view: [],            edit: ["sendTexts"] },
  { id: "reports",   label: "Reports",   editable: false, view: ["seeReportsPnl", "seeProfit", "seeTotalSales"], edit: ["seeReportsPnl", "seeProfit", "seeTotalSales"] },
  { id: "budget",    label: "Budget",    editable: false, view: ["seeCostsBudget"], edit: ["seeCostsBudget"] },
  { id: "settings",  label: "Customize", editable: true,  view: [],            edit: ["editSettings", "editCatalog"] },
];
const ALL_PERM_FLAGS = ["seeProfit", "seeReportsPnl", "seeTotalSales", "seeCostsBudget", "seeBalances", "seeInventory", "viewInvoices", "editClients", "editSchedule", "editHistory", "editCatalog", "editSettings", "editInventory", "canImport", "completeStops", "sendTexts", "canInvoice"];

// Preset roles — a baseline a per-person override builds on top of.
const PERM_PRESETS = {
  admin: {
    label: "Admin",
    desc: "Full access to every tab.",
    build: () => Object.fromEntries(PERMISSION_TABS.map(t => [t.id, "edit"])),
  },
  technician: {
    label: "Technician",
    desc: "Run the schedule; view clients and inventory.",
    build: () => ({
      dashboard: "edit", clients: "view", schedule: "edit", invoices: "hidden",
      inventory: "view", estimates: "hidden", comms: "edit",
      reports: "hidden", budget: "hidden", settings: "hidden",
    }),
  },
};

// Fill any missing tabs (e.g. ones added in a later release) as hidden.
function normalizeTabAccess(ta) {
  const out = {};
  PERMISSION_TABS.forEach(t => { out[t.id] = (ta && ta[t.id]) ? ta[t.id] : "hidden"; });
  // The old standalone Messages / Reminders tabs folded into Comms — carry prior access forward so no
  // staff member silently loses the hub. NB: the tab modes are strings and "hidden" is truthy, so a
  // plain `ta.messages || ta.reminders` would wrongly pick "hidden" over a real "edit". Rank them and
  // keep the STRONGEST non-hidden of the two, so the Comms tab shows whenever either was visible.
  if (ta && !ta.comms && (ta.messages || ta.reminders)) {
    const rank = { hidden: 0, view: 1, edit: 2 };
    out.comms = [ta.messages, ta.reminders].filter(Boolean).reduce((a, b) => ((rank[b] || 0) > (rank[a] || 0) ? b : a));
  }
  return out;
}

// Resolve a per-tab access map into the flat perms object the app reads.
function tabAccessToPerms(tabAccess) {
  const ta = normalizeTabAccess(tabAccess);
  const on = new Set();
  PERMISSION_TABS.forEach(t => {
    const mode = ta[t.id];
    if (mode === "hidden") return;
    t.view.forEach(f => on.add(f));
    if (mode === "edit") t.edit.forEach(f => on.add(f));
  });
  const perms = { isAdmin: false, tabAccess: ta };
  ALL_PERM_FLAGS.forEach(f => { perms[f] = on.has(f); });
  return perms;
}

// Starting per-tab map derived from a member's current (legacy) permissions, so
// opening an existing member in the new editor reflects what they already have.
function deriveTabAccess(member) {
  if (member?.tabAccess) return normalizeTabAccess(member.tabAccess);
  const p = memberPerms(member);
  const ta = {};
  PERMISSION_TABS.forEach(t => {
    if (p.isAdmin) { ta[t.id] = "edit"; return; }
    const visible = t.view.length ? t.view.some(f => p[f]) : true;
    if (!visible) { ta[t.id] = "hidden"; return; }
    if (!t.editable) { ta[t.id] = "edit"; return; }
    const canEdit = t.edit.length ? t.edit.every(f => p[f]) : true;
    ta[t.id] = canEdit ? "edit" : "view";
  });
  return ta;
}

// resolve a member's permission set into the same shape the app reads everywhere
function memberPerms(member) {
  const role = member?.role || "field";
  const isAdmin = role === "owner";
  if (isAdmin) {
    const all = { isAdmin: true, tabAccess: null, editInventory: true };
    ALL_PERM_FLAGS.forEach(f => { all[f] = true; });
    return applyFinePerms(all, member);
  }
  // New per-tab model takes precedence when present.
  if (member?.tabAccess) return applyFinePerms(tabAccessToPerms(member.tabAccess), member);
  // Legacy role / custom flags.
  const src = role === "custom" ? (member?.perms || {}) : (ROLE_PRESETS[role] || ROLE_PRESETS.field);
  const P = (k, dflt) => (src[k] !== undefined ? !!src[k] : dflt);
  const out = {
    isAdmin: false,
    tabAccess: null,
    seeProfit: P("canSeeProfit", false),
    seeReportsPnl: P("canSeeReportsPnl", false),
    seeTotalSales: P("canSeeTotalSales", false),
    seeCostsBudget: P("canSeeCostsBudget", false),
    seeBalances: P("canSeeBalances", true),
    seeInventory: P("canSeeInventory", false),
    viewInvoices: P("canViewInvoices", false),
    editClients: P("canEditClients", false),
    editSchedule: P("canEditSchedule", true),
    editHistory: P("canEditHistory", false),
    editCatalog: P("canEditCatalog", false),
    editSettings: P("canEditSettings", false),
    canImport: P("canImport", false),
    completeStops: P("canCompleteStops", true),
    sendTexts: P("canSendTexts", true),
    canInvoice: P("canInvoice", false),
  };
  out.editInventory = out.seeInventory; // legacy parity: viewing inventory allowed editing
  return applyFinePerms(out, member);
}

// Fine-grained permission overlay. Each granular flag DEFAULTS to its coarse parent
// (so existing members keep the same effective access), and the owner can override
// individual ones in the staff editor's "Advanced permissions" section. Stored on
// member.fine = { <flag>: bool }. Owners (isAdmin) always get everything.
function applyFinePerms(out, member) {
  const fine = (member && member.fine) || {};
  const adm = !!out.isAdmin;
  const g = (key, base) => adm ? true : (fine[key] !== undefined ? !!fine[key] : !!base);
  // Inventory cost/pricing — sensitive, so OFF by default for staff (opt-in).
  out.seeInventoryCost  = g("seeInventoryCost", false);
  // Invoice actions — default to the coarse "Manage Invoices" capability.
  out.invoiceCreate     = g("invoiceCreate",     out.canInvoice);
  out.invoiceSend       = g("invoiceSend",       out.canInvoice);
  out.invoiceMarkPaid   = g("invoiceMarkPaid",   out.canInvoice);
  out.invoiceDelete     = g("invoiceDelete",     out.canInvoice);
  // Client deletion — default to the coarse "edit clients" capability.
  out.deleteClients     = g("deleteClients",     out.editClients);
  // Settings by section — default to the coarse capability that gated each today
  // (branding/messaging under App Settings; costs under the Costs & Budget grant).
  out.editBranding      = g("editBranding",      out.editSettings);
  out.editCosts         = g("editCosts",         out.seeCostsBudget);
  out.editNotifications = g("editNotifications", out.editSettings);
  // Schedule actions — default to the coarse "edit schedule" capability.
  out.scheduleAddRemove = g("scheduleAddRemove", out.editSchedule);
  out.scheduleReorder   = g("scheduleReorder",   out.editSchedule);
  // Comms sections — the hub folds Messages, the Leads inbox, Reminders, Broadcast, automation
  // Settings, and the activity Log into one tab. The Comms tab toggle (tabAccess.comms) is the
  // MASTER: when it's Hidden, every section is off (cg gates on commsOn), so a stale fine flag can
  // never resurrect a hidden hub. When it's Visible, Messages defaults ON (existing staff keep their
  // message access) and every other section is owner-sensitive → OFF by default (opt-in). A fine
  // override still fine-tunes any section, and the owner (adm) always gets everything.
  const commsOn = adm || (out.tabAccess ? out.tabAccess.comms !== "hidden" : true);
  const cg = (key, base) => adm ? true : (commsOn && g(key, base));
  out.commsMessages  = cg("commsMessages",  true);
  out.commsInbox     = cg("commsInbox",     false);
  out.commsReminders = cg("commsReminders", false);
  out.commsBroadcast = cg("commsBroadcast", false);
  out.commsSettings  = cg("commsSettings",  false);
  out.commsLog       = cg("commsLog",       false);
  return out;
}

// The Comms hub is visible when the viewer can see at least one of its sections (owner sees all).
const COMMS_SECTION_FLAGS = ["commsMessages", "commsInbox", "commsReminders", "commsBroadcast", "commsSettings", "commsLog"];
const canSeeComms = (perms) => !!perms && (perms.isAdmin || COMMS_SECTION_FLAGS.some(f => perms[f]));

// Is a nav tab visible to this permission set?
function isTabVisible(n, perms) {
  if (!n) return false;
  // Comms visibility is driven purely by its per-section flags (which already encode the tab master),
  // so the nav entry appears exactly when the route will render — no separate ownerOnly/tabAccess gate.
  if (n.id === "comms") return canSeeComms(perms);
  if (n.ownerOnly && !perms.isAdmin) return false;
  if (perms.tabAccess) return perms.tabAccess[n.id] !== "hidden"; // per-tab model is authoritative
  if (n.perm && !perms[n.perm]) return false;
  if (n.permAny && !perms.isAdmin && !n.permAny.some(k => perms[k])) return false;
  return true;
}
// Human label for a member's access level (handles owner, presets, and custom).
function memberRoleLabel(member) {
  if (!member) return "Staff";
  if (member.role === "owner") return "Owner / Admin";
  if (member.tabAccess) {
    const ta = normalizeTabAccess(member.tabAccess);
    for (const p of Object.values(PERM_PRESETS)) {
      const built = normalizeTabAccess(p.build());
      if (PERMISSION_TABS.every(t => built[t.id] === ta[t.id])) return p.label;
    }
    return "Custom";
  }
  return roleLabel(member.role);
}
// initials for an avatar chip
const initials = (name) => (name || "?").trim().split(/\s+/).map(w => w[0]).slice(0, 2).join("").toUpperCase();
// the owner account the preview signs into by default (so you land in admin view, not a login wall)
const DEFAULT_OWNER_ID = (DEFAULT_TEAM.find(m => m.role === "owner") || DEFAULT_TEAM[0] || {}).id || "e1";
// the labor rate to bill for a stop: assigned member's rate if set, else the global rate
const laborRateFor = (assigneeId, team, costs) => {
  const m = (team || []).find(e => e.id === assigneeId);
  const r = m && m.rate !== "" && m.rate != null ? parseFloat(m.rate) : NaN;
  return isNaN(r) ? (parseFloat(costs?.hourlyRate) || 0) : r;
};

// Combine address parts into one line: "123 Main St, Elverson, PA 19520"
const assembleAddress = ({ street, city, state, zip } = {}) => {
  const s = (street || "").trim();
  const c = (city || "").trim();
  const st = (state || "").trim();
  const z = (zip || "").trim();
  const cityState = [c, [st, z].filter(Boolean).join(" ")].filter(Boolean).join(", ");
  return [s, cityState].filter(Boolean).join(", ");
};
// Best-effort split of a single address string back into parts (for older records)
const splitAddress = (addr) => {
  const blank = { street: "", city: "", state: "", zip: "" };
  if (!addr) return blank;
  const parts = String(addr).split(",").map(s => s.trim()).filter(Boolean);
  if (parts.length === 0) return { ...blank, street: String(addr).trim() };
  const out = { ...blank, street: parts[0] || "" };
  const pullZip = (str) => { const m = str.match(/^(.*?)\s+([\d][\d-]*)$/); return m ? { head: m[1].trim(), zip: m[2].trim() } : { head: str.trim(), zip: "" }; };
  if (parts.length >= 3) {
    out.city = parts[1];
    const { head, zip } = pullZip(parts.slice(2).join(" "));
    out.state = head; out.zip = zip;
  } else if (parts.length === 2) {
    const { head, zip } = pullZip(parts[1]);
    out.zip = zip;
    const toks = head.split(/\s+/).filter(Boolean);
    if (zip && toks.length >= 2) { out.state = toks[toks.length - 1]; out.city = toks.slice(0, -1).join(" "); }
    else if (zip) { out.state = head; }
    else { out.city = head; }
  }
  return out;
};

const AppCtx = createContext(null);

// Catches render crashes in a section and shows the error instead of a blank screen
class SectionErrorBoundary extends Component {
  constructor(props) { super(props); this.state = { error: null }; }
  static getDerivedStateFromError(error) { return { error }; }
  componentDidCatch(error, info) { console.error("Section crashed:", error, info); }
  render() {
    if (this.state.error) {
      return (
        <div style={{ padding: 20, margin: "12px 0", borderRadius: 14, background: "rgba(192,57,43,0.06)", border: "1px solid rgba(192,57,43,0.3)" }}>
          <div style={{ fontSize: 14, fontWeight: 800, color: "#C0392B", marginBottom: 8 }}>This section hit an error</div>
          <div style={{ fontSize: 12, color: "#6b7280", lineHeight: 1.5, fontFamily: "monospace", wordBreak: "break-word" }}>
            {String(this.state.error?.message || this.state.error)}
          </div>
          <button onClick={() => this.setState({ error: null })}
            style={{ marginTop: 14, background: "#C0392B", color: "#fff", border: "none", borderRadius: 10, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>
            Try again
          </button>
        </div>
      );
    }
    return this.props.children;
  }
}
// Null-safe: the client portal renders OUTSIDE the AppCtx provider, so the raw
// context value is null there. Returning {} lets components safely destructure
// (e.g. `const { tiers } = useApp()`) and fall back to their own defaults instead
// of crashing the whole portal to a blank/red screen.
const useApp = () => useContext(AppCtx) || {};

