// Build the report text from the template + a completed-visit record.
// includeUsage=false omits the water-tests/treatments lines (the email renders those as a
// prominent table via `rows` instead); the portal/text versions keep them inline.
function renderReport(email, ctx, { plain = false, includeUsage = true } = {}) {
  const lines = [];
  lines.push(`Hi ${ctx.firstName},`);
  lines.push("");
  lines.push(email.intro);
  lines.push("");
  lines.push(`Service: ${ctx.serviceType}`);
  lines.push(`Date: ${ctx.date}`);
  if (ctx.tech) lines.push(`Technician: ${ctx.tech}`);
  lines.push("");
  if (ctx.notes) { lines.push("Work completed:"); lines.push(ctx.notes); lines.push(""); }
  // Water tests — list every reading the tech recorded (full panel), so clients who
  // rely on the emailed/texted report (not the app) get the complete picture.
  if (includeUsage && email.showReadings) {
    const entries = ctx.readings && typeof ctx.readings === "object"
      ? Object.entries(ctx.readings).filter(([, v]) => v !== "" && v != null && v !== "—")
      : [["pH", ctx.ph], ["Ammonia", ctx.ammonia], ["Nitrite", ctx.nitrite], ["Temperature", ctx.temp]].filter(([, v]) => v && v !== "—");
    if (entries.length) {
      lines.push("WATER TESTS");
      entries.forEach(([k, v]) => lines.push(`  • ${k}: ${v}`));
      lines.push("");
    }
  }
  // Treatments applied — name + amount (oz), so the report stands on its own.
  if (includeUsage && Array.isArray(ctx.treatmentsUsed) && ctx.treatmentsUsed.length) {
    lines.push("WATER TREATMENTS APPLIED");
    ctx.treatmentsUsed.forEach(t => lines.push(`  • ${t.name}: ${t.oz} ${t.unit || "oz"}`));
    lines.push("");
  }
  if (email.showPhotosNote && ctx.photoCount > 0) {
    const beforeCt = ctx.photosBeforeCount || 0;
    const afterCt  = ctx.photosAfterCount  || 0;
    const otherCt  = ctx.photoCount - beforeCt - afterCt;
    const parts = [];
    if (beforeCt) parts.push(`${beforeCt} before`);
    if (afterCt)  parts.push(`${afterCt} after`);
    if (otherCt)  parts.push(`${otherCt} additional`);
    const photoDesc = parts.length ? ` (${parts.join(", ")})` : "";
    lines.push(`We took ${ctx.photoCount} photo${ctx.photoCount === 1 ? "" : "s"}${photoDesc} during today's visit — you can view them anytime in your client portal.`);
    lines.push("");
  }
  lines.push(email.signoff);
  lines.push("");
  lines.push(`— The ${ctx.company} Team`);
  return lines.join("\n");
}

// Compress an image — keeps original quality unless result exceeds 1MB,
// then iteratively reduces quality by 0.05 until it fits.
// Downscale a stored photo (data URL) to an email-friendly size so several can ride along
// in the report email without blowing the serverless request limit (~4.5MB).
function shrinkForEmail(dataUrl, maxDim = 1000, quality = 0.6) {
  return new Promise((resolve) => {
    try {
      const img = new Image();
      img.onload = () => {
        let { width, height } = img;
        if (width > height && width > maxDim) { height = Math.round(height * maxDim / width); width = maxDim; }
        else if (height > maxDim) { width = Math.round(width * maxDim / height); height = maxDim; }
        const canvas = document.createElement("canvas");
        canvas.width = width; canvas.height = height;
        canvas.getContext("2d").drawImage(img, 0, 0, width, height);
        resolve(canvas.toDataURL("image/jpeg", quality));
      };
      img.onerror = () => resolve(dataUrl);
      img.src = dataUrl;
    } catch (_) { resolve(dataUrl); }
  });
}

function compressImage(file, maxDim = 1600) {
  const MAX_BYTES = 1 * 1024 * 1024; // 1 MB
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const img = new Image();
      img.onload = () => {
        let { width, height } = img;
        // Only downscale if the image is very large (keep detail)
        if (width > height && width > maxDim) { height = Math.round(height * maxDim / width); width = maxDim; }
        else if (height > maxDim) { width = Math.round(width * maxDim / height); height = maxDim; }

        const canvas = document.createElement("canvas");
        canvas.width = width;
        canvas.height = height;
        canvas.getContext("2d").drawImage(img, 0, 0, width, height);

        // Start at full quality, step down only if needed
        let quality = 0.95;
        let result  = "";
        try {
          do {
            result  = canvas.toDataURL("image/jpeg", quality);
            // base64 is ~4/3 the binary size
            const approxBytes = Math.round((result.length - 22) * 3 / 4);
            if (approxBytes <= MAX_BYTES) break;
            quality = Math.round((quality - 0.05) * 100) / 100;
          } while (quality >= 0.30);
          resolve(result);
        } catch (err) {
          resolve(e.target.result); // fallback to original
        }
      };
      img.onerror = () => resolve(e.target.result);
      img.src = e.target.result;
    };
    // Build 15, 7B — never leave the promise unsettled if the read fails (corrupt/HEIC/large
    // file, permission), which froze/crashed photo capture. Resolve empty and let the caller skip.
    reader.onerror = () => resolve("");
    try { reader.readAsDataURL(file); } catch (_) { resolve(""); }
  });
}

// ── Photo storage ─────────────────────────────────────────────────────────────
// Photos live in Supabase Storage (bucket `client-media`), not inline in the DB. Inline base64
// bloated app_state until reads/writes timed out (the 2026-06-24 outage). We store the public URL;
// <img src> renders it the same. Every helper falls back gracefully so a photo is never lost.
async function uploadToStorage(dataUrl) {
  try {
    if (!dataUrl || typeof dataUrl !== "string" || !dataUrl.startsWith("data:")) return dataUrl; // already a URL / empty
    const blob = await (await fetch(dataUrl)).blob();
    const type = blob.type || "image/jpeg";
    const ext = (type.split("/")[1] || "jpg").replace("jpeg", "jpg").replace(/\+xml$/, "");
    const path = `media/${Date.now()}-${Math.random().toString(36).slice(2, 10)}.${ext}`;
    const { error } = await supabase.storage.from("client-media").upload(path, blob, { contentType: type, upsert: false });
    if (error) { console.warn("[storage] upload failed, keeping inline:", error.message); return dataUrl; } // fallback: inline
    return supabase.storage.from("client-media").getPublicUrl(path).data.publicUrl || dataUrl;
  } catch (e) { console.warn("[storage] upload error, keeping inline:", e && e.message); return dataUrl; }
}
// Compress a captured file, then move it to Storage. Returns a Storage URL (or an inline data-URL
// fallback if the upload failed), or "" if the file couldn't be decoded (e.g. HEIC) — caller skips "".
async function compressAndUpload(file, maxDim = 1280) {
  const dataUrl = await compressImage(file, maxDim);
  if (!dataUrl || !dataUrl.startsWith("data:image")) return "";
  return uploadToStorage(dataUrl);
}
// Resolve any photo src (inline data URL OR Storage URL) to a base64 data URL — for places that must
// embed the actual bytes (e.g. email). Returns "" on failure so the caller skips it.
async function toDataUrl(src) {
  if (!src || typeof src !== "string") return "";
  if (src.startsWith("data:")) return src;
  try {
    const blob = await (await fetch(src)).blob();
    return await new Promise(r => { const fr = new FileReader(); fr.onload = () => r(fr.result); fr.onerror = () => r(""); fr.readAsDataURL(blob); });
  } catch (_) { return ""; }
}

// ─────────────────────────────────────────────
const planMeta = (plan, T, tiers, div) => {
  if (!plan) return { bg: T.surfaceAlt, text: T.textMuted, color: T.textMuted, label: "No tier" };
  const divKey = div || "Pond";
  const divTierSet = (tiers || {})[divKey] || (tiers || {});
  const tierColor = divTierSet[plan]?.color;
  return ({
    Premium:   { bg: tierColor || T.primary,  text: "#fff", color: "#fff" },
    Signature: { bg: tierColor || "#6366F1",   text: "#fff", color: "#fff" },
    Essential: { bg: tierColor || T.surfaceAlt, text: tierColor ? "#fff" : T.text, color: tierColor ? "#fff" : T.text },
  }[plan] || { bg: T.surfaceAlt, text: T.textMuted, color: T.textMuted, label: plan });
};

const statusColor = (s, T) => ({
  Good:          T.accent,
  Monitor:       T.warning,
  "Replace Soon": T.primary,
}[s] || T.textMuted);

// Parse the loose date strings used on equipment (MM/YYYY, MM/DD/YYYY, YYYY-MM-DD).
// Returns { date, hasDay } or null. hasDay=false when only month/year is known.
const parseEqDate = (s) => {
  if (!s) return null;
  const v = String(s).trim();
  let m;
  if ((m = v.match(/^(\d{1,2})\/(\d{4})$/)))            return { date: new Date(+m[2], +m[1] - 1, 1), hasDay: false };
  if ((m = v.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/))) return { date: new Date(+m[3], +m[1] - 1, +m[2]), hasDay: true };
  if ((m = v.match(/^(\d{4})-(\d{1,2})-(\d{1,2})$/)))   return { date: new Date(+m[1], +m[2] - 1, +m[3]), hasDay: true };
  if ((m = v.match(/^(\d{2})(\d{4})$/)))                return { date: new Date(+m[2], +m[1] - 1, 1), hasDay: false }; // MMYYYY typed without a slash, e.g. "012024"
  // A bare digit run (e.g. "012024") must NOT fall through to new Date(): some engines (iOS
  // WKWebView) misread it as a year far in the future, which blew up warranty math.
  if (/^\d+$/.test(v)) return null;
  const d = new Date(v);
  return isNaN(d) ? null : { date: d, hasDay: true };
};
// Display a stored equipment date nicely ("Jan 2024") when we can parse it; else show it raw.
const fmtEqDate = (s) => {
  const p = parseEqDate(s);
  if (!p) return s || "";
  return p.date.toLocaleDateString("en-US", p.hasDay ? { month: "short", day: "numeric", year: "numeric" } : { month: "short", year: "numeric" });
};

// Equipment warranty: expiration = (purchase or install date) + length. Returns null
// until both a base date and a positive warranty length are present (never invented).
const warrantyInfo = (eq) => {
  if (!eq) return null;
  const len = parseFloat(eq.warrantyLength);
  if (!len || len <= 0) return null;
  const base = parseEqDate(eq.purchaseDate || eq.installed);
  if (!base) return null;
  const months = (eq.warrantyUnit || "years") === "months" ? Math.round(len) : Math.round(len * 12);
  const expiry = new Date(base.date);
  expiry.setMonth(expiry.getMonth() + months);
  const today = new Date(); today.setHours(0, 0, 0, 0);
  const exp0 = new Date(expiry); exp0.setHours(0, 0, 0, 0);
  const active = exp0 >= today;
  const monthsLeft = active ? Math.max(0, Math.round((exp0 - today) / (1000 * 60 * 60 * 24 * 30.44))) : 0;
  const label = base.hasDay
    ? exp0.toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })
    : exp0.toLocaleDateString("en-US", { month: "short", year: "numeric" });
  return { active, monthsLeft, label };
};

// Replacement / service-life schedule for a piece of equipment: next-due = (last replaced, else
// installed) + the replace-every interval (months). Returns null until both exist (never invented).
// status: ok | soon (within 60 days) | overdue. Powers the due badge + owner alerts (e.g. UV yearly).
const equipmentDue = (eq) => {
  if (!eq) return null;
  const every = parseFloat(eq.replaceEveryMonths);
  if (!every || every <= 0) return null;
  const base = parseEqDate(eq.lastReplaced || eq.installed);
  if (!base) return null;
  const due0 = new Date(base.date); due0.setMonth(due0.getMonth() + Math.round(every)); due0.setHours(0, 0, 0, 0);
  const today = new Date(); today.setHours(0, 0, 0, 0);
  const days = Math.round((due0 - today) / 86400000);
  const status = days < 0 ? "overdue" : days <= 60 ? "soon" : "ok";
  return { due: due0, days, status, label: due0.toLocaleDateString("en-US", { month: "short", year: "numeric" }) };
};

// Shared client-name comparator + the canonical list for ANY client picker:
// active clients only (inactive excluded), sorted A–Z by name. Status/name come
// straight from existing client data — nothing hardcoded. Use this everywhere a
// client is chosen (schedule, route, add-stop, invoice, estimate, message…) so
// every picker stays consistent and future pickers inherit the same behavior.
const byClientName = (a, b) => (a?.name || "").localeCompare(b?.name || "");
const selectableClients = (clients) => (clients || [])
  .filter(c => c && (c.status || "Active") !== "Inactive")
  .slice()
  .sort(byClientName);

// Sum revenue/cost/profit from completed jobs in a given month (default: current)
function monthActuals(clients, when = new Date(), invoices = []) {
  const m = when.getMonth(), y = when.getFullYear();
  let revenue = 0, cost = 0, jobs = 0;

  // Profit from what's IN THE APP: REVENUE = invoices marked Paid this month (their totals now come
  // straight from QuickBooks), COST = what's logged on completed-job breakdowns (+ any invoice line
  // costs). So the number moves with money collected. Falls back to logged-job revenue only when no
  // invoice has been paid yet this month.
  (clients || []).forEach(c => (c.history || []).forEach(h => {
    if (!h.breakdown) return;
    const [mm, dd, yy] = (h.date || "").split("/").map(Number);
    if (mm - 1 === m && yy === y) { cost += h.breakdown.total || 0; jobs += 1; }
  }));
  (invoices || []).forEach(iv => {
    if (iv.status !== "Paid" && effectiveStatus(iv) !== "Paid") return;
    const paidDate = iv.paidDate || iv.date;
    let d = null;
    if (paidDate) {
      if (paidDate.includes("/")) { const [mm, dd, yy] = paidDate.split("/").map(Number); d = new Date(yy, mm - 1, dd); }
      else d = new Date(paidDate);
    }
    if (d && d.getMonth() === m && d.getFullYear() === y) {
      const t = invoiceTotals(iv);
      revenue += t.total;
      if (t.cost) cost += t.cost;
    }
  });
  if (revenue === 0) {
    (clients || []).forEach(c => (c.history || []).forEach(h => {
      if (!h.breakdown) return;
      const [mm, dd, yy] = (h.date || "").split("/").map(Number);
      if (mm - 1 === m && yy === y) revenue += h.breakdown.revenue || 0;
    }));
  }

  return { revenue, cost, profit: revenue - cost, jobs };
}

// Sum this month's completed-job cost breakdowns into category buckets — the auto-filled "actuals" for
// the budget. Keys line up with the expense-line `src` values (labor / gas / cogs / equipment / etc.).
function monthCostActuals(clients, when = new Date()) {
  const m = when.getMonth(), y = when.getFullYear();
  const n = (v) => parseFloat(v) || 0;
  const a = { labor: 0, gas: 0, cogs: 0, equipment: 0, insurance: 0, overhead: 0 };
  (clients || []).forEach(c => (c.history || []).forEach(h => {
    const b = h && h.breakdown; if (!b) return;
    const [mm, , yy] = (h.date || "").split("/").map(Number);
    if (mm - 1 !== m || yy !== y) return;
    a.labor += n(b.labor); a.gas += n(b.gas);
    a.cogs += n(b.treatment) + n(b.parts) + n(b.product);
    a.equipment += n(b.equipment); a.insurance += n(b.insurance); a.overhead += n(b.overhead);
  }));
  return a;
}

// Debt payoff math: months to clear a balance at a monthly payment + APR, plus total interest. Returns
// { months, totalInterest, neverPaysOff? } — neverPaysOff when the payment can't cover the interest.
function debtPayoff(balance, apr, payment) {
  const B = parseFloat(balance) || 0, P = parseFloat(payment) || 0, r = (parseFloat(apr) || 0) / 1200;
  if (B <= 0) return { months: 0, totalInterest: 0, paid: true };
  if (P <= 0) return null;
  if (r === 0) { const months = Math.ceil(B / P); return { months, totalInterest: 0 }; }
  if (P <= B * r) return { months: Infinity, totalInterest: Infinity, neverPaysOff: true };
  const months = Math.ceil(-Math.log(1 - (B * r) / P) / Math.log(1 + r));
  return { months, totalInterest: Math.max(0, P * months - B) };
}
// Add N months to today → a "Mon YYYY" label.
function monthsOutLabel(months) {
  if (!isFinite(months)) return "—";
  const d = new Date(); d.setDate(1); d.setMonth(d.getMonth() + months);
  return d.toLocaleDateString("en-US", { month: "short", year: "numeric" });
}

// derive outstanding balances + equipment flags into alert items
function deriveAlerts(clients, invoices, catalog) {
  const alerts = [];
  (clients || []).forEach(c => {
    (c.equipment || []).forEach(e => {
      if (e.status && e.status !== "Good") alerts.push({ icon: "warning", title: `${c.name} — ${e.name}`, sub: `Marked "${e.status}"`, type: "equipment" });
      const due = equipmentDue(e);
      if (due && due.status === "overdue") alerts.push({ icon: "warning", title: `${c.name} — ${e.name}`, sub: `Replacement overdue (was due ${due.label})`, type: "equipment" });
      else if (due && due.status === "soon") alerts.push({ icon: "warning", title: `${c.name} — ${e.name}`, sub: `Replacement due ${due.label}`, type: "equipment" });
      const w = warrantyInfo(e);
      if (w && w.active && w.monthsLeft <= 2) alerts.push({ icon: "warning", title: `${c.name} — ${e.name}`, sub: `Warranty expires ${w.label}`, type: "equipment" });
    });
    const owed = clientOutstanding(c, invoices);
    if (owed > 0) alerts.push({ icon: "dollar", title: `${c.name} — $${owed.toFixed(2)} outstanding`, sub: "Open balance" });
  });
  // Low inventory alerts — treatments (below 32) and parts (below their lowAt)
  ((catalog && catalog.treatments) || []).forEach(t => {
    const total = invTotal(t);
    const unit = t.unit || "oz";
    if (total < 32) alerts.unshift({ icon: "warning", title: `Low stock: ${t.name}`, sub: `${total}${unit} remaining — consider restocking`, type: "inventory" });
  });
  ((catalog && catalog.parts) || []).forEach(p => {
    const total = invTotal(p);
    const low = parseFloat(p.lowAt) || 0;
    const unit = p.unit || "pieces";
    if (total < low) alerts.unshift({ icon: "warning", title: `Low stock: ${p.name}`, sub: `${total} ${unit} remaining — consider restocking`, type: "inventory" });
  });
  return alerts.slice(0, 8);
}

// ── Invoicing ──
const INVOICE_STATUSES = ["Draft", "Sent", "Paid", "Overdue"];
const invStatusColor = (s, T) => {
  const n = (s||"").charAt(0).toUpperCase() + (s||"").slice(1).toLowerCase();
  return { Draft: T.textMuted, Sent: T.primary, Paid: T.accent, Overdue: T.warning }[n] || ({ paid: T.accent, overdue: T.warning, sent: T.primary }[(s||"").toLowerCase()] || T.textMuted);
};

