    check:    <path d="M20 6 9 17l-5-5" />,
    plus:     <path d="M12 5v14M5 12h14" />,
    close:    <path d="M18 6 6 18M6 6l12 12" />,
    back:     <path d="M19 12H5M12 19l-7-7 7-7" />,
    forward:  <path d="M5 12h14M12 5l7 7-7 7" />,
