    sparkle:  <path d="M12 2l2.1 5.6a2 2 0 0 0 1.3 1.3L21 11l-5.6 2.1a2 2 0 0 0-1.3 1.3L12 20l-2.1-5.6a2 2 0 0 0-1.3-1.3L3 11l5.6-2.1a2 2 0 0 0 1.3-1.3L12 2z" />,
    // Content
